PlayerListener = {}

function PlayerListener:init()
    Listener.registerCallBack(ShowChatMessageReceiveEvent, self.onChatMessageReceive)
    Listener.registerCallBack(HurtCemaraEffectEvent, self.onHurtCemaraEffect)
end

function PlayerListener.onChatMessageReceive(isChatInformation)
    if GUIMain.isFirst then
        return true
    else
        if isChatInformation then
            return true
        else
            return false
        end
    end
end

function PlayerListener.onHurtCemaraEffect(entityPlayer)
    if entityPlayer:isOnFlyingMount() then
        return false
    end
    return true
end

return PlayerListener